=💰 *Новая заявка на расход*

*Номер*: {{ $('add request').item.json.id }}
*Проект*: {{ $('add request').item.json.title.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&') }}
*Поставщик*: {{ $('add request').item.json.vendor.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&') }}
*Категория расхода*: {{ $('add request').item.json.category.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&') }}
*Сумма*: {{ 
  Number($('add request').item.json.amount)
    .toLocaleString("uz", { 
      minimumFractionDigits: 2, 
      maximumFractionDigits: 2, 
      style: "currency", 
      currency: $('add request').item.json.currency 
    })
    .replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&')
}}
*Тип оплаты*: {{ $('add request').item.json.payment_type.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&') }}
*Назначение платежа*: {{ $('add request').item.json.payment_purpose.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&') }}
*Описание \/ зачем*: {{ $('add request').item.json.description.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&') }}
*Срочность*: {{ $('add request').item.json.urgency.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&') }}
*Заявитель*: {{ $('add request').item.json.requester.replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&') }}

{{$if(
  $('set additional fields').item.json.file_link.isEmpty(), 
  "", 
  "📎*Вложения*:\n[" + 
  $('Call \'Save file\'').item.json.filename.replace(/[_*[\]()~`>#+\-=|{}.!]/g, '\\$&') + 
  "](" + 
  $('set additional fields').item.json.file_link
    .replace(/\)/g, '\\)')
    .replace(/\\/g, '\\\\') + 
  ")\n"
)}}
🕒*Дата подачи*: {{
  new Date($('add request').item.json.submitted_at).toLocaleString('ru-RU', {
    hour: '2-digit',
    minute: '2-digit',
    day: '2-digit',
    month: 'long',
    year: 'numeric'
  }).replace(/[_*[\]()~`>#+=|{}.!-]/g, '\\$&')
}}

